{
  "version": "1.0.0-genesis",
  "created": "2026-01-06",
  "project": "MMS V1.0 GENESIS",
  "description": "Consolidate 6 MMS projects into single clean V1.0 baseline",
  "constraints": {
    "ui_framework": "PatternFly v6 (replacing BlueprintJS)",
    "state_management": "@belt/tools (replacing @zazcart/toolkit)",
    "monorepo": "DELETE packages/ folder, use npm packages directly",
    "react_version": "18.3.1 (locked)",
    "spec_target": "3000-4000 lines (consolidated)"
  },
  "magna_rules": {
    "no_nextjs": "NO SSR needed in V1. Use Vite + React directly.",
    "avoid_react_hooks": "Minimize useState/useRef/useEffect. Prioritize @belt/tools state-machine for ALL state.",
    "commit_frequently": "Always commit even small progress. Many small commits > losing work."
  },
  "phases": [
    {
      "id": "PHASE_0",
      "name": "Harness Setup",
      "status": "completed",
      "tasks": [
        {
          "id": "P0-T1",
          "description": "Backup previous harness to archive/pre-genesis/",
          "verification": [".harness/archive/pre-genesis/ exists"],
          "passes": true
        },
        {
          "id": "P0-T2",
          "description": "Create new progress.txt with full context",
          "verification": [".harness/progress.txt contains project context, constraints, and plan"],
          "passes": true
        },
        {
          "id": "P0-T3",
          "description": "Create new features.json with all phases",
          "verification": [".harness/features.json contains all 8 phases with verification criteria"],
          "passes": true
        },
        {
          "id": "P0-T4",
          "description": "Create _migration_memory/ folder",
          "verification": ["_migration_memory/ directory exists"],
          "passes": true
        }
      ]
    },
    {
      "id": "PHASE_1",
      "name": "Territory Mapping",
      "status": "completed",
      "agents": 1,
      "tasks": [
        {
          "id": "P1-T1",
          "description": "Scan all 6 nodes in ~/antonio/mms/ - count files, identify key assets, check git history",
          "verification": ["_migration_memory/00_TERRITORY_MAP.md exists with file counts, key files, git info for all 6 nodes"],
          "passes": true
        }
      ]
    },
    {
      "id": "PHASE_2",
      "name": "Knowledge Extraction",
      "status": "in_progress",
      "agents": 8,
      "parallel": true,
      "tasks": [
        {
          "id": "P2-T1",
          "description": "EXT-CANVAS: Extract from system/apps/canvas/ - LOD implementation, state management, rendering",
          "verification": ["_migration_memory/01_canvas.md exists with VERIFIED/CLAIMED categories"],
          "passes": false
        },
        {
          "id": "P2-T2",
          "description": "EXT-DOCS: Extract from system/docs/ - domain knowledge, QA protocols, specs",
          "verification": ["_migration_memory/02_domain.md exists with ECM, RAMS, EN 15380 knowledge"],
          "passes": false
        },
        {
          "id": "P2-T3",
          "description": "EXT-HARNESS: Extract from system/.harness/ + git log - decision history, learnings",
          "verification": ["_migration_memory/03_decisions.md exists with ADRs and learnings"],
          "passes": false
        },
        {
          "id": "P2-T4",
          "description": "EXT-MFC: Extract from MFC/ - solver logic, math formulas, OR-Tools patterns",
          "verification": ["_migration_memory/04_solver.md exists with KPI formulas and CP-SAT patterns"],
          "passes": false
        },
        {
          "id": "P2-T5",
          "description": "EXT-DECK: Extract from deck/ - alternative approaches, POC findings",
          "verification": ["_migration_memory/05_visualization.md exists with deck.gl learnings"],
          "passes": false
        },
        {
          "id": "P2-T6",
          "description": "EXT-PROJECTS: Extract from projects/ - historical experiments worth preserving",
          "verification": ["_migration_memory/06_experiments.md exists"],
          "passes": false
        },
        {
          "id": "P2-T7",
          "description": "EXT-DESIGN: Extract from design/ - visual specifications from mockup images",
          "verification": ["_migration_memory/07_visual_spec.md exists with UI patterns"],
          "passes": false
        },
        {
          "id": "P2-T8",
          "description": "EXT-MARKET: Extract competitor analysis from all repos",
          "verification": ["_migration_memory/08_market.md exists with competitor gaps"],
          "passes": false
        }
      ]
    },
    {
      "id": "PHASE_3",
      "name": "Technology Research",
      "status": "pending",
      "agents": 3,
      "parallel": true,
      "note": "Research happens HERE, not before extraction",
      "tasks": [
        {
          "id": "P3-T1",
          "description": "TECH-PF: Deep dive PatternFly v6 - components, BlueprintJS mapping, integration",
          "verification": ["_migration_memory/10_patternfly.md exists with component mapping and code examples"],
          "passes": false
        },
        {
          "id": "P3-T2",
          "description": "TECH-BELT: Analyze @belt/tools npm package - APIs, migration from local toolkit",
          "verification": ["_migration_memory/11_belt_tools.md exists with createSlice, createMachine patterns"],
          "passes": false
        },
        {
          "id": "P3-T3",
          "description": "TECH-CANVAS: Compare canvas technologies - R3F vs deck.gl vs alternatives with benchmarks",
          "verification": ["_migration_memory/12_canvas_tech.md exists with recommendation and evidence"],
          "passes": false
        }
      ]
    },
    {
      "id": "PHASE_4",
      "name": "Cross-Validation",
      "status": "pending",
      "agents": 4,
      "parallel": true,
      "tasks": [
        {
          "id": "P4-T1",
          "description": "VAL-MATH: Verify mathematical formulas consistency across sources",
          "verification": ["_migration_memory/20_math_validation.md exists with CONFLICTS/GAPS/VERIFIED"],
          "passes": false
        },
        {
          "id": "P4-T2",
          "description": "VAL-DOMAIN: Verify domain terminology correctness (ECM, RAMS, EN 15380)",
          "verification": ["_migration_memory/21_domain_validation.md exists"],
          "passes": false
        },
        {
          "id": "P4-T3",
          "description": "VAL-TECH: Verify technical claims (does code actually run?)",
          "verification": ["_migration_memory/22_tech_validation.md exists"],
          "passes": false
        },
        {
          "id": "P4-T4",
          "description": "VAL-PERF: Verify performance claims (60fps, TypedArrays, RBush)",
          "verification": ["_migration_memory/23_perf_validation.md exists"],
          "passes": false
        }
      ]
    },
    {
      "id": "PHASE_5",
      "name": "Decision Debates",
      "status": "pending",
      "agents": 4,
      "pattern": "3 advocates + 1 synthesizer",
      "topics": ["Canvas technology", "Spec structure", "V1.0 scope", "PatternFly integration"],
      "tasks": [
        {
          "id": "P5-T1",
          "description": "DEB-SIMPLE: Write 500-word position for simplest approach",
          "verification": ["_migration_memory/30_debate_simple.md exists"],
          "passes": false
        },
        {
          "id": "P5-T2",
          "description": "DEB-COMPLETE: Write 500-word position for most comprehensive approach",
          "verification": ["_migration_memory/31_debate_complete.md exists"],
          "passes": false
        },
        {
          "id": "P5-T3",
          "description": "DEB-PERF: Write 500-word position for performance-first approach",
          "verification": ["_migration_memory/32_debate_perf.md exists"],
          "passes": false
        },
        {
          "id": "P5-T4",
          "description": "DEB-SYNTH: Read all positions, produce consensus with evidence",
          "verification": ["_migration_memory/35_DECISIONS.md exists with justified final decisions"],
          "passes": false
        }
      ]
    },
    {
      "id": "PHASE_6",
      "name": "Specification Writing",
      "status": "pending",
      "agents": 4,
      "pattern": "3 writers + 1 editor",
      "target": "docs/SPECIFICATION.md (~3000-4000 lines)",
      "tasks": [
        {
          "id": "P6-T1",
          "description": "SPEC-DOMAIN: Write Part I - Domain (ECM, RAMS, Railway terminology, Math formulas)",
          "verification": ["docs/SPECIFICATION.md Part I complete"],
          "passes": false
        },
        {
          "id": "P6-T2",
          "description": "SPEC-ARCH: Write Part II - Architecture (Canvas, State, API, Data structures)",
          "verification": ["docs/SPECIFICATION.md Part II complete"],
          "passes": false
        },
        {
          "id": "P6-T3",
          "description": "SPEC-UX: Write Part III - UX (PatternFly components, Design system, Demo strategy)",
          "verification": ["docs/SPECIFICATION.md Part III complete"],
          "passes": false
        },
        {
          "id": "P6-T4",
          "description": "SPEC-EDIT: Final pass - consistency, formatting, deduplication",
          "verification": ["docs/SPECIFICATION.md is final, ~3000-4000 lines, no historical notes"],
          "passes": false
        }
      ]
    },
    {
      "id": "PHASE_7",
      "name": "Repository Cleanup",
      "status": "pending",
      "agents": 1,
      "tasks": [
        {
          "id": "P7-T1",
          "description": "Create backup branch (backup/pre-v1-YYYYMMDD)",
          "verification": ["git branch -a shows backup branch"],
          "passes": false
        },
        {
          "id": "P7-T2",
          "description": "Delete packages/ folder (no monorepo)",
          "verification": ["packages/ directory does not exist"],
          "passes": false
        },
        {
          "id": "P7-T3",
          "description": "Delete old docs (keep only SPECIFICATION.md)",
          "verification": ["docs/ contains only SPECIFICATION.md"],
          "passes": false
        },
        {
          "id": "P7-T4",
          "description": "Update dependencies (PatternFly v6, @belt/tools, remove @zazcart)",
          "verification": ["package.json has @patternfly/react-core, @belt/tools, no @zazcart"],
          "passes": false
        },
        {
          "id": "P7-T5",
          "description": "Delete _migration_memory/ (git preserves history)",
          "verification": ["_migration_memory/ does not exist"],
          "passes": false
        },
        {
          "id": "P7-T6",
          "description": "Update CLAUDE.md for V1.0",
          "verification": ["CLAUDE.md references V1.0 stack and conventions"],
          "passes": false
        },
        {
          "id": "P7-T7",
          "description": "Commit V1.0 baseline",
          "verification": ["git log shows V1.0 genesis commit"],
          "passes": false
        }
      ]
    },
    {
      "id": "PHASE_8",
      "name": "Implementation",
      "status": "pending",
      "pattern": "Harness protocol: one feature per session",
      "tasks": [
        {
          "id": "F001",
          "category": "foundation",
          "description": "Vite + React 18 + PatternFly v6 scaffold",
          "verification": ["npm run dev starts", "PatternFly components render", "No console errors"],
          "passes": false
        },
        {
          "id": "F002",
          "category": "foundation",
          "description": "Storybook 8 setup with PatternFly theme",
          "verification": ["npm run storybook starts", "Sample story renders"],
          "passes": false
        },
        {
          "id": "F003",
          "category": "foundation",
          "description": "@belt/tools integration",
          "verification": ["createSlice works", "State updates trigger re-renders"],
          "passes": false
        },
        {
          "id": "F004",
          "category": "canvas",
          "description": "Canvas container component (accepts data props)",
          "verification": ["Component renders WebGL canvas", "Accepts train/task data"],
          "passes": false
        },
        {
          "id": "F005",
          "category": "canvas",
          "description": "Macro LOD layer (heatmap, single draw call)",
          "verification": ["Heatmap renders at zoom < 0.5", "Yellow-orange-red gradient"],
          "passes": false
        },
        {
          "id": "F006",
          "category": "canvas",
          "description": "Meso LOD layer (task blocks, InstancedMesh)",
          "verification": ["Task blocks render at 0.5-2x zoom", "Colors by type"],
          "passes": false
        },
        {
          "id": "F007",
          "category": "canvas",
          "description": "Micro LOD layer (detail cards, HTML overlay)",
          "verification": ["Detail cards render at zoom > 2x", "Labels visible"],
          "passes": false
        },
        {
          "id": "F008",
          "category": "canvas",
          "description": "LOD transitions (crossfade 0.1 zoom units)",
          "verification": ["Smooth crossfade between layers", "No pop-in"],
          "passes": false
        },
        {
          "id": "F009",
          "category": "canvas",
          "description": "Pan/Zoom controls",
          "verification": ["Drag to pan", "Scroll to zoom", "Zoom centers on cursor"],
          "passes": false
        },
        {
          "id": "F010",
          "category": "canvas",
          "description": "60fps verification (performance test)",
          "verification": ["Stats.js shows 60fps", "No frame drops during pan/zoom"],
          "passes": false
        },
        {
          "id": "F011",
          "category": "ui",
          "description": "Train sidebar (PatternFly Table)",
          "verification": ["Sidebar shows train list", "Syncs with canvas scroll"],
          "passes": false
        },
        {
          "id": "F012",
          "category": "ui",
          "description": "Timeline header",
          "verification": ["Date labels render", "Adaptive granularity by zoom"],
          "passes": false
        },
        {
          "id": "F013",
          "category": "ui",
          "description": "Minimap",
          "verification": ["Minimap shows full timeline", "Viewport indicator visible"],
          "passes": false
        },
        {
          "id": "F014",
          "category": "ui",
          "description": "Task details (PatternFly Drawer)",
          "verification": ["Click task opens drawer", "Shows task details"],
          "passes": false
        },
        {
          "id": "F015",
          "category": "ui",
          "description": "Keyboard navigation",
          "verification": ["Tab focuses tasks", "Arrow keys navigate", "Enter selects"],
          "passes": false
        },
        {
          "id": "F016",
          "category": "solver",
          "description": "Mock API with realistic data",
          "verification": ["API returns train/task data", "Realistic Dubai Metro values"],
          "passes": false
        },
        {
          "id": "F017",
          "category": "solver",
          "description": "Real solver connection",
          "verification": ["Connects to Python OR-Tools solver", "Returns recommendations"],
          "passes": false
        },
        {
          "id": "F018",
          "category": "solver",
          "description": "Allocation workflow UI",
          "verification": ["Allocation flow visible", "3+ justifications per recommendation"],
          "passes": false
        },
        {
          "id": "F019",
          "category": "solver",
          "description": "What-If simulation",
          "verification": ["Drag task shows projection", "Response < 10 seconds"],
          "passes": false
        },
        {
          "id": "F020",
          "category": "solver",
          "description": "Demo mode with scripted scenarios",
          "verification": ["12-minute demo flow works", "Wow moments hit"],
          "passes": false
        }
      ]
    }
  ]
}
